  `created_by` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `source` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `requirements` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `objectives` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `metadata` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `campus_courses_code_unique` (`code`),
  UNIQUE KEY `campus_courses_slug_unique` (`slug`),
  KEY `campus_courses_category_id_foreign` (`category_id`),
  KEY `campus_courses_season_id_is_active_index` (`season_id`,`is_active`),
  KEY `campus_courses_is_public_index` (`is_public`),
