INSERT INTO `notifications` VALUES (1,'Provant notificacions','Estem fent una prova de notificaction a un grup de persones que tenen rol d\'admin',NULL,NULL,0,0,'new',2,'role','admin',NULL,NULL,1,'2026-03-10 10:52:24',0,0,0,'2026-03-10 10:52:24','2026-03-28 06:21:31','2026-03-28 06:21:31'),(2,'Prova de notificació a comptabilitat','Estem provant el sistema de notifications a membres de comptabilitat! \r\n\r\nSi has rebut aquest missatge, ens agradaria rebre confirmació, tant si eres o no membre de l\'Equip de comptabilitat \r\n\r\nET Equip Técnic de la UPG \r\ncampus@upg.cat\r\n\r\nGràcies',NULL,NULL,0,0,'new',2,'role','treasury',NULL,NULL,1,'2026-03-10 10:59:55',1,0,0,'2026-03-10 10:59:55','2026-03-28 06:21:31','2026-03-28 06:21:31'),(3,'Prova','Estem provant el sistema de notifications a membres de la UPG! \r\n\r\nSi has rebut aquest missatge, ens agradaria rebre confirmació pots respondre a campus@upg.cat\r\n\r\nET Equip Técnic de la UPG \r\ncampus@upg.cat\r\n\r\nGràcies',NULL,NULL,0,0,'system',2,'specific',NULL,'[\"583\"]',NULL,1,'2026-03-10 11:06:44',0,0,0,'2026-03-10 11:06:44','2026-03-28 06:21:31','2026-03-28 06:21:31'),(4,'Provant notifications','Provant notifications en dev',NULL,NULL,0,0,'new',2,'role','super-admin',NULL,NULL,1,'2026-03-10 13:16:23',1,0,0,'2026-03-10 13:16:23','2026-03-28 06:21:31','2026-03-28 06:21:31'),(5,'Provant Notifications','Enviament de notifications',NULL,NULL,0,0,'new',2,'role','super-admin',NULL,NULL,1,'2026-03-10 13:25:26',1,0,0,'2026-03-10 13:25:26','2026-03-28 06:21:31','2026-03-28 06:21:31'),(6,'Provant notifications','Enviant notifications a totes les persones del rol admin',NULL,NULL,0,0,'new',2,'role','admin',NULL,NULL,1,'2026-03-10 13:27:01',0,0,0,'2026-03-10 13:27:01','2026-03-28 06:21:31','2026-03-28 06:21:31'),(7,'Betatester','Has rebut un missatge on et demana que omplis les dades, com ho faran els resta de profes.\r\nSiusplau prova el formulari que hem preparat per confirmar les dades bancàries.',NULL,NULL,0,0,'new',2,'specific',NULL,'[\"58\"]',NULL,1,'2026-03-10 18:39:27',1,0,0,'2026-03-10 18:39:27','2026-03-28 06:21:31','2026-03-28 06:21:31'),(8,'Provant','Aquest missate es de seguretat, volem comprovar que no arriba al destinatario en periode de proves',NULL,NULL,0,0,'new',2,'role','super-admin',NULL,NULL,1,'2026-03-14 09:48:49',1,0,0,'2026-03-14 09:48:49','2026-03-28 06:21:31','2026-03-28 06:21:31'),(9,'No rebràs aquesta notification','Aquest missate es de seguretat, volem comprovar que no arriba al destinatario en periode de proves',NULL,NULL,0,0,'new',2,'specific',NULL,'[\"582\", \"583\"]',NULL,1,'2026-03-14 09:51:15',1,0,0,'2026-03-14 09:51:15','2026-03-28 06:21:31','2026-03-28 06:21:31'),(10,'prova buida','no dic res',NULL,NULL,0,0,'new',2,'specific',NULL,'[\"583\"]',NULL,1,'2026-03-14 09:57:10',1,0,0,'2026-03-14 09:57:10','2026-03-14 10:31:37','2026-03-14 10:31:37'),(11,'prova nula','espero',NULL,NULL,0,0,'new',2,'specific',NULL,'[\"583\"]',NULL,1,'2026-03-14 10:07:29',1,0,0,'2026-03-14 10:07:29','2026-03-14 10:31:35','2026-03-14 10:31:35'),(12,'prova nova','sqw 3 r3 r4433',NULL,NULL,0,0,'new',2,'role','admin',NULL,NULL,1,'2026-03-14 10:11:11',1,0,0,'2026-03-14 10:11:11','2026-03-14 10:31:27','2026-03-14 10:31:27'),(13,'a pepe','un missatge que no debe llegar',NULL,NULL,0,0,'new',2,'specific',NULL,'[\"583\", \"586\"]',NULL,1,'2026-03-14 10:12:38',1,0,0,'2026-03-14 10:12:38','2026-03-14 10:31:25','2026-03-14 10:31:25'),(14,'a pepon','cabezon',NULL,NULL,0,0,'new',2,'specific',NULL,'[\"583\", \"586\"]',NULL,1,'2026-03-14 10:15:05',1,0,0,'2026-03-14 10:15:05','2026-03-14 10:31:22','2026-03-14 10:31:22'),(15,'pepon es','un muñeco con cara de carton',NULL,NULL,0,0,'new',2,'role','admin',NULL,NULL,1,'2026-03-14 10:20:12',1,0,0,'2026-03-14 10:20:12','2026-03-14 10:31:17','2026-03-14 10:31:17'),(16,'proveta','no hi ha forma',NULL,NULL,0,0,'new',2,'specific',NULL,'[\"583\", \"586\"]',NULL,1,'2026-03-14 10:28:49',1,0,0,'2026-03-14 10:28:49','2026-03-14 10:31:12','2026-03-14 10:31:12'),(17,'proveta AAA','A AAA',NULL,NULL,0,0,'new',2,'specific',NULL,'[\"539\"]',NULL,1,'2026-03-14 10:30:48',1,0,0,'2026-03-14 10:30:48','2026-03-14 10:31:08','2026-03-14 10:31:08'),(18,'🧪 NOTIFICACIÓ DE PROVA - 12:34:54','Aquesta és una prova del sistema de notificacions amb redirecció d\'emails a campus@upg.cat',NULL,NULL,0,0,'email',1,'specific',NULL,'[1]',NULL,1,'2026-03-14 10:34:54',0,0,0,'2026-03-14 10:34:54','2026-03-28 06:21:31','2026-03-28 06:21:31'),(19,'🎓 AVISO CURS 2025-26','Estimats alumnes,\n\nAquesta és una notificació de prova del sistema campus.\nVerifiqueu que esteu rebent correctament les comunicacions.\n\nSalutacions,\nProfessor',NULL,NULL,0,0,'email',58,'campus_teacher_students',NULL,NULL,NULL,1,'2026-03-14 10:42:10',1,0,0,'2026-03-14 10:42:10','2026-03-14 13:02:44','2026-03-14 13:02:44'),(20,'📢 COMUNICACIÓN A PROFESORES','Estimats professors,\n\nAquesta és una comunicació de prova per a tots els professors del campus.\nVerifiqueu que esteu rebent correctament les notificacions del sistema.\n\nGràcies per la vostra atenció.\nAdministració Campus',NULL,NULL,0,0,'email',1,'campus_manager_teachers',NULL,NULL,NULL,1,'2026-03-14 10:43:19',1,0,0,'2026-03-14 10:43:19','2026-03-14 13:02:44','2026-03-14 13:02:44'),(21,'🎓 BIENVENIDA AL CURSO BETTES-001','Estimats alumnes del curs Beta Tester (BETTES-001),\n\nBenvinguts al nou curs! Aquesta és una notificació de prova per verificar que el sistema de comunicacions funciona correctament.\n\nEl curs comença properament i estarem contentos de comptar amb la vostra participació.\n\nPer a qualsevol dubte, no dubteu a contactar amb el professor.\n\nSalutacions,\nJosep M. SEGURA (Professor)',NULL,NULL,0,0,'email',58,'campus_teacher_students',NULL,NULL,NULL,1,'2026-03-14 11:38:39',1,0,0,'2026-03-14 11:38:39','2026-03-14 13:02:44','2026-03-14 13:02:44'),(22,'🎯 NOTIFICACIÓN ESPECÍFICA - BETTES-001','Estimats alumnes del curs Beta Tester (BETTES-001),\n\nAquesta és una notificació de prova per al grup específic d\'