/*!40000 ALTER TABLE `release_notes` DISABLE KEYS */;
INSERT INTO `release_notes` VALUES (1,'Release 1.0.0','release-1.0.0','1.0.0','minor','published','5 canvis: 2 novetats, 1 correccions','Transformació completa de l\'experiència de generació de PDFs per professors:\n\n✨ **Millores Visuals**:\n- Estils professionals corporatius UPG (Helvetica, colors #3490dc)\n- Seccions de declaracions RGPD amb caixes destacades\n- Signatura digital i footer compliment legal\n\n🎨 **Experiència d\'Usuari**:\n- Detecció intel·ligent de PDFs existents\n- Botons contextuals segon estat\n- Llistat de PDFs amb límit de 3 elements\n\n🔧 **Infraestructura**:\n- Preparació per futures sincronitzacions\n- Estructura de models i serveis ben definida\n\n📊 **Impacte**:\n- 49 professors amb dades bancàries encriptades\n- 44 IBANs protegits (89.8% del total)\n- Qualitat PDF millorada significativament','[{\"title\": \"PDF Professional\", \"description\": \"Estils UPG i tipografia Helvetica\"}, {\"title\": \"Detecció Intel·ligent\", \"description\": \"Sistema que detecta PDFs existents\"}, {\"title\": \"Llistat de PDFs\", \"description\": \"Historial amb límit de 3 elements\"}]','[]','[{\"date\": \"2026-03-25\", \"hash\": \"9a957ce70f24078efd546fe37e932229a1819c8d\", \"title\": \"Fix: improve logging structure to avoid encryption issues\", \"author\": \"Pepe artacho org\"}]','[]','[\"admin\", \"campus\", \"dashboard\"]',NULL,'[{\"date\": \"2026-03-25\", \"hash\": \"ce11dc9412d8756a6f098b904319901282413b7f\", \"author\": \"Pepe artacho org\", \"message\": \"feat: implementar sistema complet de codis de professors amigables\"}, {\"date\": \"2026-03-25\", \"hash\": \"eb2c9aacd2133499a2753e52eb8e4ef1fa2a1b60\", \"author\": \"Pepe artacho org\", \"message\": \"feat: nou algoritme generació codis amigables\"}, {\"date\": \"2026-03-25\", \"hash\": \"9a957ce70f24078efd546fe37e932229a1819c8d\", \"author\": \"Pepe artacho org\", \"message\": \"Fix: improve logging structure to avoid encryption issues\"}, {\"date\": \"2026-03-25\", \"hash\": \"49f6dece36ce5075889f4670761a9d0eb7ddebdc\", \"author\": \"Pepe artacho org\", \"message\": \"Add teachers card to admin dashboard with detailed statistics\"}, {\"date\": \"2026-03-25\", \"hash\": \"f469ef2a7229e7adf148ff577ee8d199a825355d\", \"author\": \"Pepe artacho org\", \"message\": \"Add forgot password link to welcome page navigation\"}]','2026-03-25 16:52:20',1,1,'2026-03-25 16:51:18','2026-04-01 16:27:51'),(2,'PDF Teacher Profile v1.0.0','pdf-teacher-profile-v1.0.0','1.0.0','minor','draft','Sistema de PDF professional per professors','Millores visuals i funcionals en PDFs per professors.\r\n✅ Generació PDFs\r\n✅ Descàrrega PDFs\r\n✅ Emmagatzematge\r\n✅ Vista bàsica','[{\"title\": \"PDF Professional\", \"description\": \"Estils UPG i tipografia Helvetica\"}, {\"title\": \"Detecció Intel·ligent\", \"description\": \"Sistema que detecta PDFs existents\"}]',NULL,NULL,NULL,'[\"teacher\", \"dashboard\"]',NULL,'[\"0cc358e\", \"e4c4db1\", \"9c10b43\", \"0aff20e\"]',NULL,1,NULL,'2026-04-01 16:26:38','2026-04-01 16:26:38'),(3,'PDF Teacher Profile v2.0.0 - Llistat i Optimitzacions','pdf-teacher-profile-v2.0.0---llistat-i-optimitzacions','2.0.0','minor','published','Afegit llistat de PDFs generats amb límit de 3 elements','Noves funcionalitats: llistat de PDFs, botó intel·ligent, interfície optimitzada:\r\n✅ Dashboard amb indicadors de 3 estats\r\n✅ Configuració de data límit PDF\r\n✅ Sistema de congelació de dades bancàries\r\n✅ Accés per rols (Admin/Treasury)\r\n✅ Vistes específiques per treasury\r\n✅ Protecció durant períodes de pagament\r\n✅ Validació automàtica de dates\r\n✅ Correcció d\'errors crítics\r\n✅ Optimització de cache\r\n✅ Millora de UX i UI','[{\"title\": \"Llistat de PDFs\", \"description\": \"Historial amb límit de 3 elements\"}, {\"title\": \"Botó Intel·ligent\", \"description\": \"Desactivat si PDF existeix\"}]',NULL,NULL,NULL,'[\"teacher\", \"dashboard\"]',NULL,'[\"0cc358e\", \"e4c4db1\", \"9c10b43\", \"0aff20e\", \"210ec4f\"]','2026-04-01 17:10:54',1,1,'2026-04-01 17:10:24','2026-04-01 17:10:54');
/*!40000 ALTER TABLE `release_notes` ENABLE KEYS */;
UNLOCK TABLES;

